{
  "name": "b-trees-b-trees-example-1",
  "private": true,
  "version": "0.1.0",
  "type": "commonjs",
  "scripts": {
    "start": "node server.js"
  }
}

/**
 * File: scenario.js
 * What it does: Declares the topic focus and tunable knobs for this example.
 */
module.exports = {
  topic: 'b-trees-b-trees',
  title: 'B Trees B Trees',
  focus: 'Full app demonstrating B Trees B Trees behavior with interactive endpoints.',
  behavior: 'Full app demonstrating B Trees B Trees behavior with interactive endpoints.',
  knobs: {
    simulateLatencyMs: 120,
    sampleSize: 20,
  },
};

/**
 * File: server.js
 * What it does: Minimal Node HTTP server exposing a topic simulation and a tiny UI.
 */
const http = require('http');
const fs = require('fs');
const path = require('path');
const {{ runSimulation }} = require('./simulate');
const scenario = require('./scenario');

function send(res, status, body, headers = {{}}) {{
  res.writeHead(status, {{ 'Content-Type': 'application/json', ...headers }});
  res.end(JSON.stringify(body, null, 2));
}}

function serveFile(res, filePath, type) {{
  const data = fs.readFileSync(filePath);
  res.writeHead(200, {{ 'Content-Type': type }});
  res.end(data);
}}

const server = http.createServer(async (req, res) => {{
  if (req.url === '/' || req.url === '/index.html') {{
    return serveFile(res, path.join(__dirname, 'public', 'index.html'), 'text/html');
  }}
  if (req.url === '/app.js') {{
    return serveFile(res, path.join(__dirname, 'public', 'app.js'), 'application/javascript');
  }}
  if (req.url === '/styles.css') {{
    return serveFile(res, path.join(__dirname, 'public', 'styles.css'), 'text/css');
  }}

  if (req.url.startsWith('/api/run')) {{
    const url = new URL(req.url, 'http://localhost');
    const input = url.searchParams.get('input') || 'alpha';
    const result = await runSimulation(input, scenario);
    return send(res, 200, result);
  }}

  if (req.url.startsWith('/api/scenario')) {{
    return send(res, 200, {{ scenario }});
  }}

  res.writeHead(404, {{ 'Content-Type': 'text/plain' }});
  res.end('Not found');
}});

const port = process.env.PORT || 3000;
server.listen(port, () => {{
  console.log(`Server running on http://localhost:${{port}}`);
}});

/**
 * File: simulate.js
 * What it does: Topic-specific simulation logic with simple, deterministic metrics.
 */
function scoreFromInput(input, base) {
  return base + (input.length * 7) % 100;
}

async function runSimulation(input, scenario) {
  const primary = scoreFromInput(input, 30);
  const secondary = scoreFromInput(input, 12);
  return {
    scenario: { title: scenario.title, focus: scenario.focus },
    input,
    behavior: scenario.behavior,
    metrics: {
      b_metric: primary,
      trees_metric: secondary,
      sampleSize: scenario.knobs.sampleSize,
    },
    ts: new Date().toISOString(),
  };
}

module.exports = { runSimulation };

/**
 * File: demo.js
 * What it does: Highlights production considerations for this topic.
 */
const summary = {
  topic: 'B Trees B Trees',
  focus: 'Full app demonstrating B Trees B Trees behavior with interactive endpoints.',
  considerations: [
    'SLO alignment and measurable signals',
    'Failure mode impact and mitigation',
    'Safe rollout and rollback planning',
  ],
};

console.log(summary);

/**
 * File: demo.js
 * What it does: Highlights interview tradeoffs and decision points.
 */
const summary = {
  topic: 'B Trees B Trees',
  focus: 'Full app demonstrating B Trees B Trees behavior with interactive endpoints.',
  tradeoffs: [
    'Latency vs correctness',
    'Cost vs operational complexity',
    'Simplicity vs scalability',
  ],
};

console.log(summary);

