    res.end("Not found");
    return;
  }

  let didError = false;
  const stream = renderToPipeableStream(e(App, null), {
    onShellReady() {
      res.statusCode = didError ? 500 : 200;
      res.setHeader("Content-Type", "text/html; charset=utf-8");
      stream.pipe(res);
    },
    onError(err) {
      didError = true;
