import { useMemo, useState } from "react";

function expensiveCompute(seed: number) {
  let acc = seed;
  for (let i = 0; i < 350_000; i += 1) acc = (acc * 1103515245 + 12345) % 1_000_003;
  return acc;
}

export default function HeavyWidget({ label }: { label: string }) {
