export function mean(values: number[]) {
  if (!values.length) return 0;
  return values.reduce((a, b) => a + b, 0) / values.length;
}

export function percentile(values: number[], q: number) {
  if (!values.length) return 0;
  const sorted = [...values].sort((a, b) => a - b);
  const idx = Math.floor(q * (sorted.length - 1));
  return sorted[Math.max(0, Math.min(sorted.length - 1, idx))];
}

function sampleWithReplacement(values: number[], n: number) {
  const out: number[] = [];
  for (let i = 0; i < n; i += 1) {
    const idx = Math.floor(Math.random() * values.length);
    out.push(values[idx]);
  }
  return out;
}

export function bootstrapDelta(params: {
  baseline: number[];
  experiment: number[];
  iters: number;
  statistic: (values: number[]) => number;
}) {
  const { baseline, experiment, iters, statistic } = params;
  const n0 = baseline.length;
  const n1 = experiment.length;
  const deltas: number[] = [];

  for (let i = 0; i < iters; i += 1) {
    const b = sampleWithReplacement(baseline, n0);
    const e = sampleWithReplacement(experiment, n1);
    deltas.push(statistic(e) - statistic(b));
  }

  deltas.sort((a, b) => a - b);
  const p = (q: number) => percentile(deltas, q);
  const median = p(0.5);
  const ciLow = p(0.025);
  const ciHigh = p(0.975);
  const probPositive = deltas.filter((d) => d > 0).length / deltas.length;

  return { median, ciLow, ciHigh, probPositive };
}

import { bootstrapDelta, percentile } from "./bootstrap";
import { simulateLatencySamples } from "./simulate";

const baseline = simulateLatencySamples({ n: 400, p50: 80, jitter: 12, tail: 350 });
const mildRegression = simulateLatencySamples({ n: 400, p50: 95, jitter: 12, tail: 350 });
const noisySmallWindow = simulateLatencySamples({ n: 40, p50: 95, jitter: 30, tail: 500 });

function p95(values: number[]) {
  return percentile(values, 0.95);
}

const mild = bootstrapDelta({ baseline, experiment: mildRegression, iters: 2000, statistic: p95 });
const noisy = bootstrapDelta({ baseline: baseline.slice(0, 40), experiment: noisySmallWindow, iters: 2000, statistic: p95 });

console.log(
  JSON.stringify(
    {
      baseline: { n: baseline.length, p95: p95(baseline) },
      experiment: { n: mildRegression.length, p95: p95(mildRegression) },
      bootstrap: mild,
      interpretation:
        "If probPositive is high and CI is mostly > 0, the p95 regression is likely real. Otherwise it may be noise.",
    },
    null,
    2,
  ),
);

console.log(
  JSON.stringify(
    {
      baseline_small_window: { n: 40, p95: p95(baseline.slice(0, 40)) },
      experiment_small_window: { n: noisySmallWindow.length, p95: p95(noisySmallWindow) },
      bootstrap: noisy,
      interpretation:
        "Small windows increase variance; you can get misleading conclusions. Extend duration or increase sample rate.",
    },
    null,
    2,
  ),
);

function normal(mu: number, sigma: number) {
  let u = 0;
  let v = 0;
  while (u === 0) u = Math.random();
  while (v === 0) v = Math.random();
  const z = Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);
  return mu + sigma * z;
}

export function simulateLatencySamples(params: { n: number; p50: number; jitter: number; tail: number }) {
  const { n, p50, jitter, tail } = params;
  const out: number[] = [];
  for (let i = 0; i < n; i += 1) {
    const base = Math.max(1, normal(p50, jitter));
    const withTail = Math.random() < 0.05 ? base + tail * Math.random() : base;
    out.push(withTail);
  }
  return out;
}

