export type BucketCounters = {
  total: number;
  good: number;
  bad: number;
};

export class TimeBuckets {
  private readonly bucketSizeMs: number;
  private readonly maxRetentionMs: number;
  private buckets: Map<number, BucketCounters> = new Map();

  constructor(params: { bucketSizeMs: number; maxRetentionMs: number }) {
    this.bucketSizeMs = params.bucketSizeMs;
    this.maxRetentionMs = params.maxRetentionMs;
  }

  ingest(tsMs: number, counters: { good: boolean }) {
    const start = Math.floor(tsMs / this.bucketSizeMs) * this.bucketSizeMs;
    const prev = this.buckets.get(start) ?? { total: 0, good: 0, bad: 0 };
    const next: BucketCounters = {
      total: prev.total + 1,
      good: prev.good + (counters.good ? 1 : 0),
      bad: prev.bad + (counters.good ? 0 : 1),
    };
    this.buckets.set(start, next);
    this.prune(tsMs);
  }

  reset() {
    this.buckets = new Map();
  }

  snapshot(params: { nowMs: number; windowMs: number }): BucketCounters {
    const { nowMs, windowMs } = params;
    const from = nowMs - windowMs;
    let total = 0;
    let good = 0;
    let bad = 0;
    for (const [start, c] of this.buckets.entries()) {
      if (start < from) continue;
      total += c.total;
      good += c.good;
      bad += c.bad;
    }
    return { total, good, bad };
  }

  private prune(nowMs: number) {
    const cutoff = nowMs - this.maxRetentionMs;
    for (const start of this.buckets.keys()) {
      if (start < cutoff) this.buckets.delete(start);
    }
  }
}

import { createHash } from "crypto";

export function stableUniform01(seed: string) {
  const digest = createHash("sha256").update(seed).digest();
  const bucket = digest.readUInt32BE(0);
  return bucket / 0xffffffff;
}

export class RecentLatencies {
  private readonly maxSize: number;
  private values: number[] = [];

  constructor(maxSize: number) {
    this.maxSize = maxSize;
  }

  push(ms: number) {
    this.values.push(ms);
    if (this.values.length > this.maxSize) this.values.shift();
  }

  reset() {
    this.values = [];
  }

  snapshot() {
    const values = [...this.values].sort((a, b) => a - b);
    const p = (q: number) => {
      if (!values.length) return 0;
      const idx = Math.floor(q * (values.length - 1));
      return values[Math.max(0, Math.min(values.length - 1, idx))];
    };
    return {
      p50Ms: p(0.5),
      p95Ms: p(0.95),
      maxMs: values.length ? values[values.length - 1] : 0,
      sampleCount: values.length,
    };
  }
}

export function clamp01(v: number) {
  if (Number.isNaN(v)) return 0;
  return Math.max(0, Math.min(1, v));
}

export function allowedBad(total: number, objective: number) {
  const budgetFraction = clamp01(1 - objective);
  return total * budgetFraction;
}

export function burnRate(params: { bad: number; total: number; objective: number }) {
  const allowed = allowedBad(params.total, params.objective);
  if (allowed === 0) return params.bad > 0 ? Number.POSITIVE_INFINITY : 0;
  return params.bad / allowed;
}

export function budgetSummary(params: { bad: number; total: number; objective: number }) {
  const allowed = allowedBad(params.total, params.objective);
  const remainingBad = allowed - params.bad;
  const remainingPct = allowed === 0 ? 1 : Math.max(0, remainingBad / allowed);
  return {
    allowedBad: allowed,
    remainingBad,
    remainingPct,
    consumedPct: 1 - remainingPct,
  };
}

export function evaluateAlerts(params: {
  burn5m: number;
  burn30m: number;
  burn1h: number;
  burn6h: number;
  remainingBudgetPct: number;
}) {
  const fastThreshold = 14.4;
  const slowThreshold = 6.0;
  const fast = params.burn5m > fastThreshold && params.burn1h > fastThreshold;
  const slow = params.burn30m > slowThreshold && params.burn6h > slowThreshold;
  const releaseFreeze = fast || slow || params.remainingBudgetPct < 0.2;
  return {
    fast: { firing: fast, threshold: fastThreshold, windows: ["5m", "1h"] as const },
    slow: { firing: slow, threshold: slowThreshold, windows: ["30m", "6h"] as const },
    releaseFreeze,
  };
}

