import { NextResponse } from "next/server";
import { z } from "zod";
import { computeEtag, getStore } from "@/lib/store";

const QuerySchema = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
});

export async function GET(req: Request) {
  const url = new URL(req.url);
  const query = QuerySchema.parse(Object.fromEntries(url.searchParams.entries()));
  const store = getStore();

  const payload = {
    version: store.feedVersion,
    items: store.items.slice(0, query.limit),
    generatedAt: new Date().toISOString(),
  };

  const etag = computeEtag({ version: payload.version, items: payload.items });
  const inm = req.headers.get("if-none-match");
  if (inm && inm === etag) {
    return new NextResponse(null, { status: 304, headers: { ETag: etag } });
  }

  return NextResponse.json(payload, {
    headers: {
      ETag: etag,
      "Cache-Control": "private, max-age=0, must-revalidate",
    },
  });
}

import { NextResponse } from "next/server";
import { getStore } from "@/lib/store";

function percentile(xs: number[], p: number) {
  if (!xs.length) return 0;
  const sorted = xs.slice().sort((a, b) => a - b);
  const idx = Math.min(sorted.length - 1, Math.floor((sorted.length - 1) * p));
  return sorted[idx];
}

export async function GET() {
  const store = getStore();
  const longtasks = store.telemetry.filter((e) => e.type === "longtask").map((e: any) => e.durationMs as number);
  const polls = store.telemetry.filter((e) => e.type === "poll") as any[];

  const bytesByMode = polls.reduce(
    (acc, p) => {
      acc[p.mode] = (acc[p.mode] ?? 0) + (p.bytes ?? 0);
      acc.total += p.bytes ?? 0;
      if (p.status === 304) acc.notModified += 1;
      if (p.status >= 200 && p.status < 300) acc.ok += 1;
      return acc;
    },
    { total: 0, ok: 0, notModified: 0, naive: 0, optimized: 0 } as Record<string, number>,
  );

  return NextResponse.json({
    ts: new Date().toISOString(),
    longtasks: {
      count: longtasks.length,
      p50: percentile(longtasks, 0.5),
      p95: percentile(longtasks, 0.95),
      max: longtasks.length ? Math.max(...longtasks) : 0,
    },
    polling: {
      totalRequests: polls.length,
      ok: bytesByMode.ok,
      notModified: bytesByMode.notModified,
      bytesTotal: bytesByMode.total,
      bytesByMode: { naive: bytesByMode.naive, optimized: bytesByMode.optimized },
    },
  });
}

import { NextResponse } from "next/server";
import { z } from "zod";
import { recordTelemetry } from "@/lib/store";

const BodySchema = z.object({
  type: z.enum(["longtask", "poll"]),
  durationMs: z.number().optional(),
  status: z.number().int().optional(),
  bytes: z.number().int().optional(),
  mode: z.enum(["naive", "optimized"]).optional(),
});

export async function POST(req: Request) {
  const body = BodySchema.parse(await req.json());
  const ts = new Date().toISOString();

  if (body.type === "longtask") {
    recordTelemetry({ type: "longtask", durationMs: body.durationMs ?? 0, ts });
  } else {
    recordTelemetry({
      type: "poll",
      status: body.status ?? 0,
      bytes: body.bytes ?? 0,
      ts,
      mode: body.mode ?? "naive",
    });
  }

  return NextResponse.json({ ok: true });
}

import { z } from "zod";

const ArgsSchema = z.object({
  baseUrl: z.string().url(),
  requests: z.coerce.number().int().min(1).max(500).default(50),
});

function parseArgs(argv: string[]) {
  const out: Record<string, string> = {};
  for (let i = 0; i < argv.length; i++) {
    const token = argv[i];
    if (!token.startsWith("--")) continue;
    const key = token.slice(2);
    const value = argv[i + 1] && !argv[i + 1].startsWith("--") ? argv[++i] : "true";
    out[key] = value;
  }
  return ArgsSchema.parse(out);
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  const baseUrl = args.baseUrl.replace(/\/$/, "");

  let etag = "";
  let bytes = 0;
  let notModified = 0;

  for (let i = 0; i < args.requests; i++) {
    const res = await fetch(`${baseUrl}/api/feed?limit=25`, {
      headers: etag ? { "If-None-Match": etag } : {},
    });
    if (res.status === 304) {
      notModified++;
      continue;
    }
    const text = await res.text();
    bytes += text.length;
    etag = res.headers.get("etag") ?? etag;
  }

  console.log(JSON.stringify({ requests: args.requests, bytesDownloaded: bytes, notModified }, null, 2));
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

