export type BreakerState = "closed" | "open" | "half_open";

export class CircuitBreaker {
  private state: BreakerState = "closed";
  private failures = 0;
  private openedAt = 0;

  constructor(
    private readonly opts: {
      failureThreshold: number;
      openForMs: number;
      halfOpenMaxCalls: number;
    },
  ) {}

  snapshot() {
    return { state: this.state, failures: this.failures, openedAt: this.openedAt };
  }

  canAttempt(now = Date.now()): boolean {
    if (this.state === "closed") return true;
    if (this.state === "open") {
      if (now - this.openedAt >= this.opts.openForMs) {
        this.state = "half_open";
        this.failures = 0;
        return true;
      }
      return false;
    }
    // half-open
    return this.failures < this.opts.halfOpenMaxCalls;
  }

  onSuccess() {
    this.state = "closed";
    this.failures = 0;
    this.openedAt = 0;
  }

  onFailure(now = Date.now()) {
    this.failures += 1;
    if (this.state === "half_open") {
      this.state = "open";
      this.openedAt = now;
      return;
    }
    if (this.failures >= this.opts.failureThreshold) {
      this.state = "open";
      this.openedAt = now;
    }
  }
}

export type RetryPolicy = {
  maxAttempts: number;
  baseDelayMs: number;
  maxDelayMs: number;
  jitterPct: number; // 0..1
};

export function backoffDelayMs(policy: RetryPolicy, attempt: number): number {
  const exp = Math.min(policy.maxDelayMs, policy.baseDelayMs * 2 ** (attempt - 1));
  const jitter = exp * policy.jitterPct * Math.random();
  return Math.floor(exp + jitter);
}

export async function withRetry<T>(params: {
  policy: RetryPolicy;
  fn: (attempt: number) => Promise<T>;
  retryable: (e: unknown) => boolean;
}): Promise<{ value: T; attempts: number }> {
  let lastErr: unknown;
  for (let attempt = 1; attempt <= params.policy.maxAttempts; attempt++) {
    try {
      const value = await params.fn(attempt);
      return { value, attempts: attempt };
    } catch (e) {
      lastErr = e;
      if (attempt === params.policy.maxAttempts || !params.retryable(e)) break;
      const d = backoffDelayMs(params.policy, attempt);
      await new Promise((r) => setTimeout(r, d));
    }
  }
  throw lastErr;
}

