type Clock = Record<string, number>;

function dominates(a: Clock, b: Clock) {
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
  let strictly = false;
  for (const k of keys) {
    const av = a[k] ?? 0;
    const bv = b[k] ?? 0;
    if (av < bv) return false;
    if (av > bv) strictly = true;
  }
  return strictly;
}

