import { InMemoryStore } from "./store.js";
import { backfillBatch, dualWritePut, readWithRepair, type MigrationState, verifyAll } from "./migration.js";

function assert(condition: unknown, msg: string): asserts condition {
  if (!condition) throw new Error(msg);
}

async function main() {
  const source = new InMemoryStore();
  const target = new InMemoryStore();

  // Initial state: only source has data.
  for (let i = 0; i < 25; i++) {
    await source.put(`seed/${String(i).padStart(2, "0")}.txt`, `seed-${i}`);
  }

  // During migration: dual-write new traffic.
  await dualWritePut(source, target, "new/a.txt", "new-a");
  await dualWritePut(source, target, "new/b.txt", "new-b");

  // Backfill in batches with a checkpoint (cursor). Simulate an interruption and resume.
  let state: MigrationState = { cursor: 0, copied: 0, verified: 0 };
  let done = false;

  for (let step = 0; step < 2; step++) {
    const r = await backfillBatch(source, target, state, 10);
    state = r.state;
    done = r.done;
    if (step === 1) break;
  }

  // Simulated crash/restart: we keep `state` and continue.
  while (!done) {
    const r = await backfillBatch(source, target, state, 10);
    state = r.state;
    done = r.done;
  }

  // Read-repair can smooth cutover: prefer target but repair misses from source.
  const rr = await readWithRepair(target, source, "seed/03.txt");
  assert(rr && rr.value === "seed-3", "read-repair should return correct value");

  // Verification step before cutover.
  const v = await verifyAll(source, target);
  assert(v.ok, `verification failed: mismatches=${v.mismatches}`);

  console.log(
    JSON.stringify(
      {
        ok: true,
        copied: state.copied,
        verification: v,
      },
      null,
      2,
    ),
  );
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

import type { ObjectStore } from "./store.js";
import { checksum } from "./store.js";

export type MigrationState = {
  cursor: number;
  copied: number;
  verified: number;
};

export async function dualWritePut(
  primary: ObjectStore,
  secondary: ObjectStore,
  key: string,
  value: string,
): Promise<void> {
  // Production note: use idempotency keys + retries and record per-store outcomes.
  await primary.put(key, value);
  await secondary.put(key, value);
}

export async function readWithRepair(
  preferred: ObjectStore,
  fallback: ObjectStore,
  key: string,
): Promise<{ value: string; repaired: boolean } | null> {
  const p = await preferred.get(key);
  if (p) return { value: p.value, repaired: false };
  const f = await fallback.get(key);
  if (!f) return null;
  await preferred.put(key, f.value);
  return { value: f.value, repaired: true };
}

export async function backfillBatch(
  source: ObjectStore,
  target: ObjectStore,
  state: MigrationState,
  batchSize: number,
): Promise<{ done: boolean; state: MigrationState }> {
  const keys = await source.listKeys();
  const batch = keys.slice(state.cursor, state.cursor + batchSize);

  for (const key of batch) {
    const src = await source.get(key);
    if (!src) continue;
    const dst = await target.get(key);
    if (dst && dst.checksum === src.checksum) continue; // idempotent
    await target.put(key, src.value);
    state.copied++;
  }

  state.cursor += batch.length;
  return { done: state.cursor >= keys.length, state };
}

export async function verifyAll(source: ObjectStore, target: ObjectStore): Promise<{ ok: boolean; mismatches: number }> {
  const keys = await source.listKeys();
  let mismatches = 0;
  for (const key of keys) {
    const s = await source.get(key);
    const t = await target.get(key);
    if (!s || !t || t.checksum !== checksum(s.value)) mismatches++;
  }
  return { ok: mismatches === 0, mismatches };
}

import crypto from "node:crypto";

export type Obj = { key: string; value: string; checksum: string; updatedAt: number };

export interface ObjectStore {
  put(key: string, value: string): Promise<Obj>;
  get(key: string): Promise<Obj | null>;
  listKeys(): Promise<string[]>;
  del(key: string): Promise<boolean>;
}

export function checksum(value: string): string {
  return crypto.createHash("sha256").update(value).digest("hex");
}

export class InMemoryStore implements ObjectStore {
  private map = new Map<string, Obj>();

  async put(key: string, value: string): Promise<Obj> {
    const obj: Obj = { key, value, checksum: checksum(value), updatedAt: Date.now() };
    this.map.set(key, obj);
    return obj;
  }

  async get(key: string): Promise<Obj | null> {
    return this.map.get(key) ?? null;
  }

  async listKeys(): Promise<string[]> {
    return [...this.map.keys()].sort();
  }

  async del(key: string): Promise<boolean> {
    return this.map.delete(key);
  }
}

