import type { ReactNode } from "react";
import "./globals.css";

export const metadata = {
  title: "Versioned API",
  description: "Backward compatibility via adapters and deprecation signaling.",
};

export default function RootLayout(props: { children: ReactNode }) {
  return (
    <html lang="en">
      <body>{props.children}</body>
    </html>
  );
}

import { z } from "zod";

export const ProfileV1Schema = z.object({
  id: z.string(),
  name: z.string(),
});
export type ProfileV1 = z.infer<typeof ProfileV1Schema>;

export const ProfileV2Schema = z.object({
  id: z.string(),
  displayName: z.string(),
  locale: z.string().default("en"),
  // Compatibility: keep v1 field so old clients survive.
  name: z.string().optional(),
});
export type ProfileV2 = z.infer<typeof ProfileV2Schema>;

export function toV1(v2: ProfileV2): ProfileV1 {
  return { id: v2.id, name: v2.name ?? v2.displayName };
}

export function toV2(v1: ProfileV1): ProfileV2 {
  return { id: v1.id, displayName: v1.name, name: v1.name, locale: "en" };
}

import type { ProfileV2 } from "./contracts";

type Store = {
  profile: ProfileV2;
};

const store: Store =
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  ((globalThis as any).__VER_STORE__ as Store | undefined) ?? {
    profile: { id: "u-1", displayName: "Ada", name: "Ada", locale: "en" },
  };

// eslint-disable-next-line @typescript-eslint/no-explicit-any
(globalThis as any).__VER_STORE__ = store;

export function getProfile(): ProfileV2 {
  return store.profile;
}

export function setProfile(p: ProfileV2) {
  store.profile = p;
}

